mapper.select:
SELECT `year_month` as yearMonth, ROUND(AVG(total), 1) as avgTotal, ROUND(SUM(total), 1) as sumTotal, ROUND(AVG(dimension_a), 1) as avgDimensionA, ROUND(SUM(dimension_a), 1) as sumDimensionA, ROUND(AVG(dimension_b), 1) as avgDimensionB, ROUND(SUM(dimension_b), 1) as sumDimensionB, ROUND(AVG(dimension_c), 1) as avgDimensionC, ROUND(SUM(dimension_c), 1) as sumDimensionC, ROUND(AVG(dimension_d), 1) as avgDimensionD, ROUND(SUM(dimension_d), 1) as sumDimensionD FROM sp_monthly_assessment WHERE is_deleted = 0
AND category IN
#{category}
AND supplier_name IN
#{supplier}
AND `year_month` IN
#{yearMonth}
GROUP BY `year_month` ORDER BY `year_month` ASC

SELECT `year_month` as yearMonth, ROUND(AVG(total), 1) as avgTotal, COUNT(CASE WHEN grade = 'A' THEN 1 END) as gradeACount, COUNT(CASE WHEN grade = 'D' THEN 1 END) as gradeDCount FROM sp_monthly_assessment WHERE is_deleted = 0
AND `year_month` = #{yearMonth}
GROUP BY `year_month` ORDER BY `year_month` DESC LIMIT 2
